const prev = $('번역 필요 여부').first().json;
const translated = $input.first().json;

const promptEn = translated.content?.[0]?.text || prev.prompt_to_engine;

return [{
  json: {
    ...prev,
    prompt_en: promptEn
  }
}];

// ✅ Creatomate 최종 영상 합성 — ai_video / slideshow 분기
const job = $input.first().json;
const productionMode = job.production_mode || 'ai_video';
const scenes = job.scene_results || [];
const apiKey = $env.CREATOMATE_API_KEY;

if (scenes.length === 0) throw new Error('scene_results가 비어있음');

let elements = [];

if (productionMode === 'slideshow') {
  // ===== SLIDESHOW: 이미지 슬라이드 + TTS + 자막 =====
  const slideDur = parseInt(job.slide_duration) || 3;
  const totalDur = scenes.length * slideDur;

  // 이미지 슬라이드
  scenes.forEach((s, i) => {
    elements.push({
      type: 'image',
      source: s.image_url,
      time: i * slideDur,
      duration: slideDur,
      fit: 'cover',
      animations: [
        { type: 'scale', fade: false, scope: 'element', start_scale: '100%', end_scale: '120%' }
      ]
    });
  });

  // TTS 나레이션 (전체 길이)
  if (job.tts_audio_url) {
    elements.push({
      type: 'audio',
      source: job.tts_audio_url,
      time: 0,
      duration: totalDur
    });
  }

  // 자막 (TTS 텍스트)
  if (job.tts_text) {
    elements.push({
      type: 'text',
      text: job.tts_text,
      time: 0,
      duration: Math.min(totalDur, 10),
      y: '80%',
      width: '90%',
      x_alignment: '50%',
      y_alignment: '50%',
      font_family: 'Noto Sans KR',
      font_weight: 700,
      font_size: '7 vmin',
      fill_color: '#ffffff',
      stroke_color: '#000000',
      stroke_width: '1.5 vmin',
      background_color: 'rgba(0,0,0,0.5)',
      background_x_padding: '3 vmin',
      background_y_padding: '2 vmin',
      background_border_radius: '1 vmin'
    });
  }
} else {
  // ===== AI_VIDEO: 기존 씬별 클립 이어붙이기 (변경 없음) =====
  const dur = parseInt(job.clip_duration) <= 4 ? 4 : 8;
  scenes.forEach((s, i) => {
    elements.push({
      type: 'video',
      source: s.video_url,
      time: i * dur,
      duration: dur,
      fit: 'cover'
    });
    if (s.audio_url) {
      elements.push({
        type: 'audio',
        source: s.audio_url,
        time: i * dur,
        duration: dur
      });
    }
  });
}

const body = {
  source: {
    output_format: 'mp4',
    width: 1080,
    height: 1920,
    elements: elements
  }
};

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.creatomate.com/v1/renders',
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'application/json'
  },
  body: body,
  json: true
});

const render = Array.isArray(resp) ? resp[0] : resp;
return [{ json: render }];

// Creatomate 렌더 폴링
const renderResponse = $input.first().json;
const renderId = renderResponse.id || (Array.isArray(renderResponse) ? renderResponse[0]?.id : null);
if (!renderId) throw new Error('renderId 없음');

const apiKey = $env.CREATOMATE_API_KEY || '';
let status = 'planned';
let url = null;
let attempts = 0;
const maxAttempts = 60;

while (!['succeeded', 'failed'].includes(status) && attempts < maxAttempts) {
  await new Promise(r => setTimeout(r, 5000));
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.creatomate.com/v1/renders/${renderId}`,
    headers: { 'Authorization': `Bearer ${apiKey}` },
    json: true
  });
  status = resp.status;
  url = resp.url;
  attempts++;
}

if (status !== 'succeeded' || !url) {
  throw new Error(`영상 렌더링 실패: ${status}`);
}

// ✅ TTS 폴링 출력에서 job 원본 데이터 병합
const prevData = $('멀티씬 순차 처리').first().json;
return [{
  json: {
    ...prevData,
    rendered_video_url: url,
    render_id: renderId
  }
}];

// ✅ 에러 핸들러 — 재시도 로직
const error = $input.first().json;
const jobId = $('큐에서 Job 꺼내기').first().json?.id;

if (!jobId) return [];

return [{
  json: {
    job_id: jobId,
    error_message: error.message || JSON.stringify(error),
    timestamp: new Date().toISOString()
  }
}];

// ✅ 영상/슬라이드쇼 처리 — production_mode 분기
const job = $input.first().json;
const productionMode = job.production_mode || 'ai_video';
let files = job.files || [];
if (typeof files === 'string') { try { files = JSON.parse(files); } catch(e) { files = []; } }

const directFiles = files.filter(f => f.use_directly !== false);
const apiKey = $env.KIEAI_API_KEY;
const promptBase = job.prompt_en || job.prompt_to_engine || job.prompt_p1;

// kie.ai 폴링 (공통)
async function pollTask(taskId) {
  for (let i = 0; i < 90; i++) {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${taskId}`,
      headers: { 'Authorization': `Bearer ${apiKey}` },
      json: true
    });
    const state = resp?.data?.state;
    if (state === 'success') {
      const result = JSON.parse(resp.data.resultJson || '{}');
      return result.resultUrls?.[0] || null;
    }
    if (state === 'failed' || state === 'fail') {
      throw new Error(`Task 실패: ${resp.data.failMsg || state}`);
    }
    await new Promise(r => setTimeout(r, 10000));
  }
  throw new Error('Task 타임아웃 (900초)');
}

// TTS 생성 (공통)
async function generateTTS(text) {
  if (!text) return null;
  const ttsResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.kie.ai/api/v1/jobs/createTask',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: {
      model: 'elevenlabs/text-to-speech-multilingual-v2',
      input: { text: text, voice_id: 'EXAVITQu4vr4xnSDxMaL' }
    },
    json: true
  });
  const ttsTaskId = ttsResp?.data?.taskId;
  if (ttsTaskId) return await pollTask.call(this, ttsTaskId);
  return null;
}

// 이미지 URL 수집
const imageUrls = directFiles
  .filter(f => f.type === 'image' && f.url)
  .map(f => f.url);

// ===== SLIDESHOW 모드 =====
if (productionMode === 'slideshow') {
  if (imageUrls.length === 0) throw new Error('slideshow 모드: 이미지가 없습니다');
  const slideDur = parseInt(job.slide_duration) || 3;
  const ttsText = job.prompt_p1 || job.topic || '';
  const audioUrl = await generateTTS.call(this, ttsText);

  return [{
    json: {
      ...job,
      production_mode: 'slideshow',
      slide_image_urls: imageUrls,
      slide_duration: slideDur,
      tts_audio_url: audioUrl,
      tts_text: ttsText,
      scene_results: imageUrls.map((url, i) => ({
        index: i,
        image_url: url,
        audio_url: i === 0 ? audioUrl : null,
        type: 'slide'
      })),
      total_scenes: imageUrls.length,
      total_duration: imageUrls.length * slideDur
    }
  }];
}

// ===== AI_VIDEO 모드 (기존 Kling 3.0 — 변경 없음) =====
if (directFiles.length === 0) {
  if (!job.prompt_p1 && !job.prompt_to_engine) throw new Error('파일과 프롬프트 모두 없음');
}

const rawDur = parseInt(job.clip_duration) || 8;
const duration = String(Math.max(3, Math.min(15, rawDur)));

const klingInput = {
  prompt: promptBase,
  aspect_ratio: '9:16',
  mode: 'std',
  sound: false,
  duration: duration
};

if (imageUrls.length > 0) {
  klingInput.image_urls = imageUrls.slice(0, 2);
}

let taskResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.kie.ai/api/v1/jobs/createTask',
  headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
  body: { model: 'kling-3.0/video', input: klingInput },
  json: true
});

if (taskResp?.code !== 200 && klingInput.image_urls) {
  delete klingInput.image_urls;
  taskResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.kie.ai/api/v1/jobs/createTask',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: { model: 'kling-3.0/video', input: klingInput },
    json: true
  });
}

const klingTaskId = taskResp?.data?.taskId;
if (!klingTaskId) throw new Error('Kling taskId 없음: ' + JSON.stringify(taskResp).substring(0, 200));

const videoUrl = await pollTask.call(this, klingTaskId);
if (!videoUrl) throw new Error('Kling 영상 URL 없음');

const audioUrl = await generateTTS.call(this, job.topic);

const sceneResults = [{
  index: 0,
  video_url: videoUrl,
  file_urls: imageUrls,
  audio_url: audioUrl,
  model: 'kling-3.0/video'
}];

return [{
  json: {
    ...job,
    production_mode: 'ai_video',
    scene_results: sceneResults,
    total_scenes: 1,
    total_duration: parseInt(duration)
  }
}];

/* === 기존 Seedance 코드 (보존) ===
