=== 기존 Seedance 코드 끝 === */

// ✅ YouTube 업로드 — OAuth token refresh + chunked upload
const job = $input.first().json;
const videoUrl = job.rendered_video_url;
if (!videoUrl) throw new Error('rendered_video_url 없음');

// 1) OAuth 토큰 갱신
const tokenResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=refresh_token&client_id=${$env.YT_CLIENT_ID}&client_secret=${$env.YT_CLIENT_SECRET}&refresh_token=${$env.YT_REFRESH_TOKEN}`,
  json: true
});
const accessToken = tokenResp.access_token;
if (!accessToken) throw new Error('YouTube token refresh 실패');

// 2) 영상 크기 확인
const headResp = await this.helpers.httpRequest({
  method: 'HEAD',
  url: videoUrl,
  returnFullResponse: true
});
const contentLength = headResp.headers?.['content-length'] || '0';

const title = job.metadata?.title || job.topic || 'AO 자동 생성 영상';
const description = job.metadata?.description || [job.topic, job.keywords].filter(Boolean).join(' - ');
const tags = job.metadata?.tags || (job.keywords ? job.keywords.split(',').map(t => t.trim()) : []);

// 3) Resumable upload 초기화
const initResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://www.googleapis.com/upload/youtube/v3/videos?uploadType=resumable&part=snippet,status',
  headers: {
    'Authorization': `Bearer ${accessToken}`,
    'Content-Type': 'application/json; charset=UTF-8',
    'X-Upload-Content-Length': contentLength,
    'X-Upload-Content-Type': 'video/mp4'
  },
  body: { snippet: { title, description, tags, categoryId: '22' }, status: { privacyStatus: 'unlisted' } },
  json: true,
  returnFullResponse: true
});

const uploadUrl = initResp.headers?.location;
if (!uploadUrl) throw new Error('resumable URL 없음');

// 4) 영상 다운로드 (Buffer)
const videoResp = await this.helpers.httpRequest({
  method: 'GET',
  url: videoUrl,
  encoding: null,
  returnFullResponse: true
});
const videoBuffer = videoResp.body;

// 5) PUT 업로드 — Node.js https 모듈 사용 (EPIPE 우회)
const https = require('https');
const url = require('url');

const uploadResult = await new Promise((resolve, reject) => {
  const parsed = new URL(uploadUrl);
  const options = {
    hostname: parsed.hostname,
    path: parsed.pathname + parsed.search,
    method: 'PUT',
    headers: {
      'Content-Type': 'video/mp4',
      'Content-Length': videoBuffer.length
    }
  };

  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try { resolve(JSON.parse(data)); }
      catch(e) { resolve({ raw: data }); }
    });
  });

  req.on('error', reject);
  req.write(videoBuffer);
  req.end();
});

const youtubeId = uploadResult?.id;
const youtubeUrl = youtubeId ? `https://youtube.com/watch?v=${youtubeId}` : null;

if (!youtubeId) throw new Error('YouTube 업로드 실패: ' + JSON.stringify(uploadResult).substring(0, 200));

return [{
  json: {
    ...job,
    youtube_video_id: youtubeId,
    youtube_url: youtubeUrl
  }
}];

