    url: `${callbackUrl}/api/productions/callback`,
    headers: { 'Content-Type': 'application/json' },
    body: {
      productionId: productionId,
      status: 'uploaded',
      youtubeVideoId: job.youtube_video_id || null,
      youtubeUrl: job.youtube_url || null,
      renderedVideoUrl: job.rendered_video_url || null,
      jobId: job.id
    },
    json: true
  });
  return [{ json: { ...job, callback_sent: true } }];
} catch(e) {
  // 콜백 실패해도 파이프라인은 성공으로 유지
  return [{ json: { ...job, callback_sent: false, callback_error: e.message } }];
