    url: `https://api.creatomate.com/v1/renders/${renderId}`,
    headers: { 'Authorization': `Bearer ${apiKey}` },
    json: true
  });
  status = resp.status;
  url = resp.url;
  attempts++;
}

if (status !== 'succeeded' || !url) {
  throw new Error(`영상 렌더링 실패: ${status}`);
}

// ✅ TTS 폴링 출력에서 job 원본 데이터 병합
const prevData = $('TTS 생성 대기 (폴링)').first().json;
return [{
  json: {
    ...prevData,
    rendered_video_url: url,
    render_id: renderId
  }
}];

// ✅ 에러 핸들러 — 재시도 로직
const error = $input.first().json;
const jobId = $('큐에서 Job 꺼내기').first().json?.id;

if (!jobId) return [];

return [{
  json: {
    job_id: jobId,
    error_message: error.message || JSON.stringify(error),
    timestamp: new Date().toISOString()
  }
}];

// ✅ kie.ai TTS 폴링 — 오디오 URL 획득
const ttsResponse = $input.first().json;
const taskId = ttsResponse?.data?.taskId;
if (!taskId) throw new Error('TTS taskId 없음 - TTS 응답: ' + JSON.stringify(ttsResponse).substring(0, 200));

const apiKey = $env.KIEAI_API_KEY || '';
const maxRetries = 30;
const interval = 5000;

let audioUrl = null;
for (let i = 0; i < maxRetries; i++) {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${taskId}`,
    headers: { 'Authorization': `Bearer ${apiKey}` },
    json: true
  });

  const state = resp?.data?.state;
  if (state === 'success') {
    const resultJson = JSON.parse(resp.data.resultJson || '{}');
    audioUrl = resultJson.resultUrls?.[0] || null;
    break;
  }
  if (state === 'failed' || resp?.data?.failMsg) {
    throw new Error(`TTS 생성 실패: ${resp.data.failMsg || state}`);
  }
  await new Promise(r => setTimeout(r, interval));
}

if (!audioUrl) throw new Error('TTS 생성 타임아웃 (150초)');

// ✅ 이전 노드 데이터 병합
const prevData = $('나레이션 생성 (Claude)').first().json;
return [{
  json: {
    ...prevData,
    tts_audio_url: audioUrl,
    tts_task_id: taskId
  }
}];

// ✅ 멀티클립 순차 처리 — clips[] 루프
const job = $input.first().json;
let clips = [];
try {
  clips = typeof job.clips === 'string' ? JSON.parse(job.clips) : (job.clips || []);
} catch(e) { clips = []; }

if (clips.length === 0) throw new Error('clips 배열이 비어있음');

const duration = String(job.clip_duration || 8);
const apiKey = $env.KIEAI_API_KEY;
const promptBase = job.prompt_en || job.prompt_to_engine || job.prompt_p1;
const clipVideos = [];

// kie.ai 폴링 헬퍼
async function pollTask(taskId, helpers) {
  for (let i = 0; i < 60; i++) {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${taskId}`,
      headers: { 'Authorization': `Bearer ${apiKey}` },
      json: true
    });
    const state = resp?.data?.state;
    if (state === 'success') {
      const result = JSON.parse(resp.data.resultJson || '{}');
      return result.resultUrls?.[0] || null;
    }
    if (state === 'failed' || state === 'fail') {
      throw new Error(`Task 실패: ${resp.data.failMsg || state}`);
    }
    await new Promise(r => setTimeout(r, 10000));
  }
  throw new Error('Task 타임아웃 (600초)');
}

for (let i = 0; i < clips.length; i++) {
  const clip = clips[i];

  // 1) 영상 프롬프트 조립: vision_analysis + scene_prompt + P1
  const parts = [];
  if (clip.vision_analysis) parts.push(`[Image: ${clip.vision_analysis}]`);
  if (clip.scene_prompt) parts.push(`[Scene: ${clip.scene_prompt}]`);
  parts.push(promptBase);
  const videoPrompt = parts.join('\n');

  // 2) Seedance createTask
  const taskResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.kie.ai/api/v1/jobs/createTask',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'bytedance/seedance-1.5-pro',
      input: {
        prompt: videoPrompt,
        input_urls: clip.image_url ? [clip.image_url] : [],
        aspect_ratio: '9:16',
        resolution: '720p',
        duration: duration,
        fixed_lens: false,
        generate_audio: false
      }
    },
    json: true
  });

  const taskId = taskResp?.data?.taskId;
  if (!taskId) throw new Error(`Clip ${i+1} Seedance taskId 없음`);

  // 3) 폴링
  const videoUrl = await pollTask(taskId, this.helpers);
  if (!videoUrl) throw new Error(`Clip ${i+1} 영상 URL 없음`);

  clipVideos.push({ index: i, video_url: videoUrl, image_url: clip.image_url || '' });
}

return [{
  json: {
    ...job,
    clip_videos: clipVideos,
    total_clips: clipVideos.length,
    total_duration: clipVideos.length * parseInt(duration)
  }
}];

// ✅ Claude API로 나레이션 대본 생성
const job = $input.first().json;
const totalDuration = job.total_duration || 40;
const clipCount = job.total_clips || 5;

const apiKey = $env.CLAUDE_API_KEY || '';

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': apiKey,
    'anthropic-version': '2023-06-01',
    'Content-Type': 'application/json'
  },
  body: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1500,
    messages: [{
      role: 'user',
      content: `다음 영상의 나레이션 대본을 작성해줘.\n\n주제: ${job.topic || ''}\n키워드: ${job.keywords || ''}\n메인 지시: ${job.prompt_p1}\n총 영상 길이: ${totalDuration}초 (${clipCount}개 장면)\n\n규칙:\n- 총 ${totalDuration}초 분량에 맞는 나레이션\n- 자연스러운 한국어\n- 나레이션 텍스트만 출력 (설명/주석 없이)`
    }]
  },
  json: true
});

const narrationScript = resp?.content?.[0]?.text || job.topic || '';

return [{
  json: {
    ...job,
    narration_script: narrationScript
  }
}];
